/// Look up the glyph bitmap for `ch`, if supported (printable ASCII only).
pub fn glyph(ch: char) -> Option<&'static [u8; 8]> {
    let code = ch as u32;
    if (0x20..=0x7E).contains(&code) {
        Some(&FONT_8X8[(code - 0x20) as usize])
    } else {
        None
    }
}
